import LiveMap from './components/LiveMap';
import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import AuthModal from './components/AuthModal';
import { authAPI, ridesAPI } from './services/api';
import wsService from './services/websocket';
import {
  Car, Bike, Users, Clock, MapPin, Navigation,
  Shield, Search, ArrowRight, DollarSign
} from 'lucide-react';

function App() {
  const [user, setUser] = useState(null);
  const [showAuthModal, setShowAuthModal] = useState(false);
  const [authMode, setAuthMode] = useState('login');
  const [currentView, setCurrentView] = useState('home');
  const [rides, setRides] = useState([]);
  const [myRides, setMyRides] = useState([]);
  const [rideTracking, setRideTracking] = useState(null);

  const [liveLocation, setLiveLocation] = useState({
    lat: 28.6139,
    lng: 77.2090
  });


  const [searchParams, setSearchParams] = useState({
    from: '',
    to: '',
    date: new Date().toISOString().split('T')[0],
    type: 'carpool'
  });

  const [newRide, setNewRide] = useState({
    type: 'carpool',
    from: '',
    to: '',
    date: '',
    time: '',
    seats: 3,
    price: 0,
    vehicleNumber: '',
    helmetAvailable: false
  });

  /* -------------------- EFFECTS -------------------- */

  useEffect(() => {
    wsService.connect();

    wsService.addListener('map', (data) => {
      if (data.type === 'location_update') {
        setLiveLocation(data.location);
      }
    });

    return () => {
      wsService.removeListener('map');
      wsService.disconnect();
    };
  }, []);

  useEffect(() => {
    const token = localStorage.getItem('token');
    const savedUser = localStorage.getItem('user');
    if (token && savedUser) {
      setUser(JSON.parse(savedUser));
    }
  }, []);

  useEffect(() => {
    if (user) fetchMyRides();
  }, [user]);

  /* -------------------- HANDLERS -------------------- */

  const handleAuthClick = (mode) => {
    setAuthMode(mode);
    setShowAuthModal(true);
  };

  const handleLogin = async (credentials, mode) => {
    const response =
      mode === 'login'
        ? await authAPI.login(credentials)
        : await authAPI.signup(credentials);

    const userData = response.data;
    localStorage.setItem('token', userData.token);
    localStorage.setItem('user', JSON.stringify(userData));
    setUser(userData);
    setShowAuthModal(false);
  };

  const handleLogout = () => {
    localStorage.clear();
    setUser(null);
    setCurrentView('home');
  };

  const handleSearch = async () => {
    const response = await ridesAPI.searchRides(searchParams);
    setRides(response.data);
    setCurrentView('search-results');
  };

  const handleOfferRide = async (e) => {
    e.preventDefault();
    await ridesAPI.createRide(newRide);
    setCurrentView('home');
  };

  const fetchMyRides = async () => {
    const response = await ridesAPI.getMyRides();
    setMyRides(response.data);
  };

  /* -------------------- UI -------------------- */

  return (
    <div className="min-h-screen bg-gray-50">

      {showAuthModal && (
        <AuthModal
          mode={authMode}
          onLogin={handleLogin}
          onClose={() => setShowAuthModal(false)}
        />
      )}

      <Header
        user={user}
        onLogout={handleLogout}
        onAuthClick={handleAuthClick}
        setCurrentView={setCurrentView}
      />

      {/* LIVE TRACKING DEMO (TEMP) */}
      <div className="max-w-7xl mx-auto px-4 mt-6 grid grid-cols-1 lg:grid-cols-3 gap-6">

  {/* LEFT PANEL */}
  <div className="bg-white rounded-xl shadow p-6 space-y-4">
    <h2 className="text-xl font-bold text-gray-800">
      Live Ride Tracking
    </h2>

    <p className="text-sm text-gray-600">
      Real-time location of the ongoing ride
    </p>

    <button
      onClick={() => wsService.trackRide('demo-ride')}
      className="w-full bg-green-600 hover:bg-green-700 text-white py-2 rounded-lg font-medium"
    >
      Start Live Tracking
    </button>

    <div className="text-sm text-gray-500">
      Status: <span className="text-green-600 font-medium">Active</span>
    </div>
  </div>

  {/* RIGHT PANEL (MAP) */}
  <div className="lg:col-span-2 bg-white rounded-xl shadow overflow-hidden">
    <LiveMap location={liveLocation} />
  </div>

</div>


      {/* HOME */}
      {currentView === 'home' && (
        <section className="py-20 bg-gradient-to-br from-blue-50 to-indigo-100">
          <div className="max-w-4xl mx-auto p-6 bg-white rounded-xl shadow">
            <h1 className="text-4xl font-bold mb-6">
              Share Your Ride, Save Money & Planet
            </h1>

            <div className="space-y-4">
              <input
                placeholder="From"
                className="w-full p-3 border rounded"
                value={searchParams.from}
                onChange={(e) =>
                  setSearchParams({ ...searchParams, from: e.target.value })
                }
              />
              <input
                placeholder="To"
                className="w-full p-3 border rounded"
                value={searchParams.to}
                onChange={(e) =>
                  setSearchParams({ ...searchParams, to: e.target.value })
                }
              />
              <button
                onClick={handleSearch}
                className="w-full bg-blue-600 text-white py-3 rounded"
              >
                Search Rides
              </button>
            </div>

            <button
              className="mt-4 text-blue-600"
              onClick={() => user ? setCurrentView('offer') : handleAuthClick('signup')}
            >
              Or offer a ride →
            </button>
          </div>
        </section>
      )}

      {/* OFFER RIDE */}
      {currentView === 'offer' && (
        <div className="max-w-2xl mx-auto bg-white p-8 rounded-xl shadow mt-10">
          <h2 className="text-2xl font-bold mb-6">Offer a Ride</h2>

          <form onSubmit={handleOfferRide} className="space-y-4">
            <input
              required
              placeholder="From"
              className="w-full p-2 border rounded"
              value={newRide.from}
              onChange={(e) => setNewRide({ ...newRide, from: e.target.value })}
            />

            <input
              required
              placeholder="To"
              className="w-full p-2 border rounded"
              value={newRide.to}
              onChange={(e) => setNewRide({ ...newRide, to: e.target.value })}
            />

            <input
              type="date"
              required
              className="w-full p-2 border rounded"
              value={newRide.date}
              onChange={(e) => setNewRide({ ...newRide, date: e.target.value })}
            />

            <input
              type="time"
              required
              className="w-full p-2 border rounded"
              value={newRide.time}
              onChange={(e) => setNewRide({ ...newRide, time: e.target.value })}
            />

            <input
              type="number"
              placeholder="Price"
              className="w-full p-2 border rounded"
              value={newRide.price}
              onChange={(e) =>
                setNewRide({ ...newRide, price: Number(e.target.value) })
              }
            />

            {/* ✅ FIXED HELMET CHECKBOX */}
            {newRide.type === 'bikepool' && (
              <div className="flex items-center gap-3">
                <input
                  type="checkbox"
                  id="helmet"
                  checked={newRide.helmetAvailable}
                  onChange={(e) =>
                    setNewRide({ ...newRide, helmetAvailable: e.target.checked })
                  }
                />
                <label htmlFor="helmet" className="text-sm text-gray-700">
                  Helmet Available
                </label>
              </div>
            )}

            <button
              type="submit"
              className="w-full bg-green-600 text-white py-3 rounded"
            >
              Offer Ride
            </button>
          </form>
        </div>
      )}
    </div>
  );
}

export default App;
